INSERT INTO online_bookstore_apeqx_books (id, title, author, price, cover_image_url, description, genre, created_at) VALUES
(gen_random_uuid(), 'The Great Gatsby', 'F. Scott Fitzgerald', 1299, 'https://picsum.photos/300/450?random=1', 'A gripping tale of wealth, love, and the American Dream set in the Jazz Age. Gatsby''s pursuit of Daisy Buchanan reveals the hollowness beneath the glittering surface of 1920s New York.', 'Fiction', NOW()),
(gen_random_uuid(), 'To Kill a Mockingbird', 'Harper Lee', 1399, 'https://picsum.photos/300/450?random=2', 'Through the eyes of a young girl named Scout, this novel explores racial injustice and moral growth in the American South. A timeless meditation on courage and compassion.', 'Fiction', NOW()),
(gen_random_uuid(), 'Pride and Prejudice', 'Jane Austen', 999, 'https://picsum.photos/300/450?random=3', 'Elizabeth Bennet navigates societal expectations and romance with wit and intelligence. This beloved classic remains a celebration of female independence and true love.', 'Fiction', NOW()),
(gen_random_uuid(), 'The Catcher in the Rye', 'J.D. Salinger', 1199, 'https://picsum.photos/300/450?random=4', 'Holden Caulfield''s disaffected voice captures the alienation of adolescence. A meditative portrait of teenage rebellion and the search for authenticity in a complex world.', 'Fiction', NOW()),
(gen_random_uuid(), '1984', 'George Orwell', 1299, 'https://picsum.photos/300/450?random=5', 'In a totalitarian future, Winston Smith fights against an oppressive regime. A haunting exploration of surveillance, control, and the power of truth.', 'Fiction', NOW()),
(gen_random_uuid(), 'The Hobbit', 'J.R.R. Tolkien', 1399, 'https://picsum.photos/300/450?random=6', 'Bilbo Baggins embarks on an unexpected adventure that transforms him from a timid hobbit into a hero. A charming prelude to an epic fantasy world.', 'Fantasy', NOW()),
(gen_random_uuid(), 'The Lord of the Rings: The Fellowship of the Ring', 'J.R.R. Tolkien', 1899, 'https://picsum.photos/300/450?random=7', 'Frodo and his companions begin a perilous journey to destroy the One Ring. An epic tale of friendship, sacrifice, and courage against overwhelming darkness.', 'Fantasy', NOW()),
(gen_random_uuid(), 'A Game of Thrones', 'George R.R. Martin', 1799, 'https://picsum.photos/300/450?random=8', 'In a land of dragons and political intrigue, noble families compete for control of the Seven Kingdoms. A complex, intricate fantasy epic with morally complex characters.', 'Fantasy', NOW()),
(gen_random_uuid(), 'The Name of the Wind', 'Patrick Rothfuss', 1599, 'https://picsum.photos/300/450?random=9', 'Kvothe recounts his transformation from a wandering magician''s son to a legendary figure. A richly imaginative fantasy infused with magic, mystery, and heart.', 'Fantasy', NOW()),
(gen_random_uuid(), 'Mistborn', 'Brandon Sanderson', 1599, 'https://picsum.photos/300/450?random=10', 'In a world of ash and oppression, a street thief discovers she holds the key to revolution. Epic fantasy with intricate magic systems and unforgettable characters.', 'Fantasy', NOW()),
(gen_random_uuid(), 'The Murders in the Rue Morgue', 'Edgar Allan Poe', 899, 'https://picsum.photos/300/450?random=11', 'C. Auguste Dupin solves a seemingly impossible crime. The tale that invented the modern detective story.', 'Mystery', NOW()),
(gen_random_uuid(), 'The Hound of the Baskervilles', 'Arthur Conan Doyle', 1099, 'https://picsum.photos/300/450?random=12', 'Sherlock Holmes and Watson confront a legendary curse on the Baskerville estate. A masterpiece of suspense and deduction.', 'Mystery', NOW()),
(gen_random_uuid(), 'And Then There Were None', 'Agatha Christie', 1199, 'https://picsum.photos/300/450?random=13', 'Ten strangers are trapped on an island, each accused of crimes and disappearing one by one. An ingeniously plotted masterpiece of mystery and suspense.', 'Mystery', NOW()),
(gen_random_uuid(), 'The Girl with the Dragon Tattoo', 'Stieg Larsson', 1699, 'https://picsum.photos/300/450?random=14', 'A journalist and a brilliant hacker investigate a decades-old disappearance. A gripping modern thriller with unforgettable characters.', 'Mystery', NOW()),
(gen_random_uuid(), 'Gone Girl', 'Gillian Flynn', 1399, 'https://picsum.photos/300/450?random=15', 'On her anniversary, Amy Dunne vanishes. Told from alternating perspectives, this psychological thriller upends every assumption about guilt and truth.', 'Mystery', NOW()),
(gen_random_uuid(), 'The Maltese Falcon', 'Dashiell Hammett', 1099, 'https://picsum.photos/300/450?random=16', 'Sam Spade chases a legendary artifact across 1920s San Francisco. A hardboiled classic that defined the noir detective genre.', 'Mystery', NOW()),
(gen_random_uuid(), 'Dune', 'Frank Herbert', 1799, 'https://picsum.photos/300/450?random=17', 'Paul Atreides is thrust into a far-future world of politics, religion, and giant sandworms. An epic space opera and meditation on power and ecology.', 'Science Fiction', NOW()),
(gen_random_uuid(), 'Foundation', 'Isaac Asimov', 1299, 'https://picsum.photos/300/450?random=18', 'Hari Seldon foresees the collapse of civilization and creates a Foundation to preserve knowledge. A visionary exploration of psychohistory and human destiny.', 'Science Fiction', NOW()),
(gen_random_uuid(), 'Neuromancer', 'William Gibson', 1299, 'https://picsum.photos/300/450?random=19', 'A washed-up computer hacker is hired for one last job in a cyberpunk future. The novel that launched the cyberpunk genre and imagined the internet.', 'Science Fiction', NOW()),
(gen_random_uuid(), 'The Martian', 'Andy Weir', 1399, 'https://picsum.photos/300/450?random=20', 'An astronaut stranded on Mars must use ingenuity and science to survive. A thrilling, optimistic tale of human resilience and problem-solving.', 'Science Fiction', NOW()),
(gen_random_uuid(), 'Snow Crash', 'Neal Stephenson', 1699, 'https://picsum.photos/300/450?random=21', 'In a dystopian near-future, a hacker uncovers a dangerous computer virus that affects both virtual and physical reality. A prescient, sprawling cyberpunk epic.', 'Science Fiction', NOW()),
(gen_random_uuid(), 'Brave New World', 'Aldous Huxley', 1299, 'https://picsum.photos/300/450?random=22', 'In a future of genetic engineering and pleasure, humanity has sacrificed freedom for stability. A chilling vision of technological control and social conformity.', 'Science Fiction', NOW()),
(gen_random_uuid(), 'Educated', 'Tara Westover', 1699, 'https://picsum.photos/300/450?random=23', 'A young woman raised by survivalists in Idaho escapes to education and self-discovery. A powerful memoir of resilience, identity, and the search for truth.', 'Biography', NOW()),
(gen_random_uuid(), 'Becoming', 'Michelle Obama', 1799, 'https://picsum.photos/300/450?random=24', 'From Chicago to the White House, Michelle Obama shares her life story with grace and candor. An inspiring memoir about identity, ambition, and service.', 'Biography', NOW()),
